void NativeVeloqrs::registerModule(
    jsi::Runtime &rt, std::shared_ptr<react::CallInvoker> callInvoker) {
  auto invoker =
      std::make_shared<uniffi_runtime::UniffiCallInvoker>(callInvoker);
  auto tm = std::make_shared<NativeVeloqrs>(rt, invoker);
  auto obj = rt.global().createFromHostObject(rt, tm);
  rt.global().setProperty(rt, "NativeVeloqrs", obj);
}

void NativeVeloqrs::unregisterModule(jsi::Runtime &rt) {
  uniffi::veloqrs::registry::clearRegistry();
}

jsi::Value NativeVeloqrs::get(jsi::Runtime &rt, const jsi::PropNameID &name) {
  try {
    return jsi::Value(rt, props.at(name.utf8(rt)));
  } catch (std::out_of_range &e) {
    return jsi::Value::undefined();
  }
}

std::vector<jsi::PropNameID> NativeVeloqrs::getPropertyNames(jsi::Runtime &rt) {
  std::vector<jsi::PropNameID> rval;
  for (auto &[key, value] : props) {
    rval.push_back(jsi::PropNameID::forUtf8(rt, key));
  }
  return rval;
}

void NativeVeloqrs::set(jsi::Runtime &rt, const jsi::PropNameID &name,
                        const jsi::Value &value) {
  props.insert_or_assign(name.utf8(rt), &value);
}

NativeVeloqrs::~NativeVeloqrs() {
  // Cleanup for callback function RustFutureContinuationCallback
  uniffi::veloqrs::cb::rustfuturecontinuationcallback::cleanup();
  // Cleanup for "free" callback function CallbackInterfaceFree
  uniffi::veloqrs::st::foreignfuture::foreignfuture::free::cleanup();
}

